                value = "\(Int((percentage.rounded(toPlaces: 2)) * 100))%"
            }
            if self.time > 0 {
                width = self.drawTwoRows(
                    first: value,
                    second: Double(self.time*60).printSecondsToHoursMinutesSeconds(short: isShortTimeFormat),
                    x: x
                ).rounded(.up)
